import os

os.makedirs("scripts", exist_ok=True)

open("scripts/moonraker.sh", "w").write("#!/bin/sh\n# moonraker.sh - Install/remove Moonraker extensions for K2 Plus\n\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\n\nMOONRAKER_CONF=$CONFIG_DIR/moonraker.conf\nSTOCK_MOONRAKER_CONF=/usr/share/moonraker/moonraker.conf\n\ninstall_moonraker_extensions() {\n    echo \"\"\n    log_info \"Installing Moonraker Extensions...\"\n    echo \"\"\n\n    # 1. Create our moonraker.conf wrapper in /mnt/UDISK\n    if [ ! -f \"$MOONRAKER_CONF\" ]; then\n        cat > \"$MOONRAKER_CONF\" << 'EOF'\n# Creality K2 Plus - Moonraker extension config\n# Managed by Creality Helper Script\n# https://github.com/sw3defy/Creality-Helper-Script-Wiki-K2-Plus\n#\n# This file loads the stock read-only Moonraker config first,\n# then extensions added by the helper script appear below.\n\n[include /usr/share/moonraker/moonraker.conf]\nEOF\n        log_success \"Created $MOONRAKER_CONF\"\n    else\n        log_info \"moonraker.conf already exists, checking include...\"\n        # Ensure include is present\n        if ! grep -q \"include /usr/share/moonraker/moonraker.conf\" \"$MOONRAKER_CONF\"; then\n            sed -i \"1s/^/[include \\/usr\\/share\\/moonraker\\/moonraker.conf]\\n\\n/\" \"$MOONRAKER_CONF\"\n            log_success \"Added stock config include to existing moonraker.conf\"\n        fi\n    fi\n\n    # 2. Patch S56moonraker to point to our config\n    patch_moonraker_startup\n\n    # 4. Restart Moonraker\n    restart_moonraker\n\n    mark_installed \"moonraker_extensions\"\n    echo \"\"\n    log_success \"Moonraker Extensions installed successfully!\"\n    echo \"\"\n    log_info \"Update Manager is now available in Fluidd under Settings \u2192 Software Updates.\"\n    log_info \"Object processing enabled (required for KAMP).\"\n    echo \"\"\n}\n\nremove_moonraker_extensions() {\n    echo \"\"\n    log_info \"Removing Moonraker Extensions...\"\n    echo \"\"\n\n    # Only remove the extensions file if it exists\n    if [ ! -f \"$MOONRAKER_CONF\" ]; then\n        log_warn \"No moonraker.conf found at $MOONRAKER_CONF \u2014 nothing to remove.\"\n        return 0\n    fi\n\n    echo \"\"\n    echo -e \"${YELLOW}WARNING: This will remove your moonraker.conf and restore the stock config.${NC}\"\n    echo \"Any other extensions (timelapse, KAMP, etc.) that added sections to\"\n    echo \"moonraker.conf will also stop working until re-installed.\"\n    echo \"\"\n    printf \"Are you sure? [y/N]: \"\n    read confirm\n    if [ \"$confirm\" != \"y\" ] && [ \"$confirm\" != \"Y\" ]; then\n        log_info \"Cancelled.\"\n        return 0\n    fi\n\n    # Restore stock moonraker startup\n    unpatch_moonraker_startup\n\n    # Archive the config rather than deleting it\n    mv \"$MOONRAKER_CONF\" \"${MOONRAKER_CONF}.removed.$(date +%Y%m%d)\"\n    log_success \"Archived moonraker.conf\"\n\n    restart_moonraker\n\n    mark_removed \"moonraker_extensions\"\n    log_success \"Moonraker Extensions removed. Stock config restored.\"\n}\n\ncase \"$1\" in\n    install) install_moonraker_extensions ;;\n    remove)  remove_moonraker_extensions ;;\n    *)       echo \"Usage: $0 [install|remove]\" ;;\nesac\n")
print("  OK scripts/moonraker.sh")

open("scripts/useful_macros.sh", "w").write("#!/bin/sh\n# useful_macros.sh - Full useful macros suite for K2 Plus\n# Includes all K1 macros adapted for K2 Plus hardware + K2 Plus-specific additions\n\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\n\nMACROS_CFG=$CONFIG_DIR/useful_macros.cfg\n\ninstall_useful_macros() {\n    echo \"\"\n    log_info \"Installing Useful Macros...\"\n    echo \"\"\n\n    cat > \"$MACROS_CFG\" << 'EOF'\n# Useful Macros \u2014 K2 Plus\n# Managed by Creality Helper Script\n# https://github.com/sw3defy/Creality-Helper-Script-K2-Plus\n#\n# Included macros:\n#   START_PRINT, END_PRINT, PAUSE, RESUME, CANCEL_PRINT\n#   PID_BED, PID_HOTEND, PID_CHAMBER\n#   BED_LEVELING, Z_TILT_CALIBRATE\n#   WARMUP (movement stress test)\n#   CHAMBER_HEAT, CHAMBER_COOL, CHAMBER_STATUS\n#   KLIPPER_BACKUP_CONFIG, KLIPPER_RESTORE_CONFIG\n#   MOONRAKER_BACKUP_DATABASE, MOONRAKER_RESTORE_DATABASE\n#   RELOAD_CAMERA\n#   SET_PRINT_STATS_INFO\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PRINT START / END\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro START_PRINT]\ndescription: Start a print \u2014 called by slicer start G-code\ngcode:\n  {% set BED_TEMP      = params.BED_TEMP|default(60)|float %}\n  {% set EXTRUDER_TEMP = params.EXTRUDER_TEMP|default(200)|float %}\n  {% set CHAMBER_TEMP  = params.CHAMBER_TEMP|default(0)|float %}\n\n  CLEAR_PAUSE\n  M220 S100   ; reset speed override\n  M221 S100   ; reset flow override\n  G90         ; absolute positioning\n  M83         ; extruder relative mode\n\n  ; Start heating bed immediately (don't wait yet)\n  M140 S{BED_TEMP}\n\n  ; Start chamber heater if a target was provided\n  {% if CHAMBER_TEMP > 0 %}\n    SET_HEATER_TEMPERATURE HEATER=chamber_heater TARGET={CHAMBER_TEMP}\n  {% endif %}\n\n  ; Home all axes\n  G28\n\n  ; Z-tilt adjustment \u2014 mandatory on K2 Plus (dual Z motors)\n  Z_TILT_ADJUST\n\n  ; Wait for bed temperature\n  M190 S{BED_TEMP}\n\n  ; Wait for chamber temperature if requested\n  {% if CHAMBER_TEMP > 0 %}\n    TEMPERATURE_WAIT SENSOR=\"heater_generic chamber_heater\" MINIMUM={CHAMBER_TEMP - 3}\n  {% endif %}\n\n  ; Pre-heat nozzle to 80% to minimise ooze during bed mesh\n  M109 S{(EXTRUDER_TEMP * 0.8)|int}\n\n  ; Adaptive or full bed mesh\n  BED_MESH_CALIBRATE\n\n  ; Full nozzle temperature\n  M109 S{EXTRUDER_TEMP}\n\n  ; Purge line (requires KAMP \u2014 skipped gracefully if not installed)\n  {% if printer['gcode_macro LINE_PURGE'] is defined %}\n    LINE_PURGE\n  {% endif %}\n\n  SET_PRINT_STATS_INFO TOTAL_LAYER=[total_layer_count]\n\n[gcode_macro END_PRINT]\ndescription: End a print \u2014 called by slicer end G-code\ngcode:\n  {% set max_x = printer.toolhead.axis_maximum.x %}\n  {% set max_y = printer.toolhead.axis_maximum.y %}\n\n  ; Small retract\n  G91\n  G1 E-2 F3600\n  G1 Z5 F600\n  G90\n\n  ; Turn off all heaters\n  M104 S0\n  M140 S0\n  SET_HEATER_TEMPERATURE HEATER=chamber_heater TARGET=0\n\n  ; Turn off fans\n  M107\n  {% if printer['gcode_macro FANS_OFF'] is defined %}\n    FANS_OFF\n  {% endif %}\n\n  ; Park toolhead and present print\n  G1 X{max_x / 2} Y{max_y - 10} F12000\n\n  ; Disable steppers (keep Z to hold position)\n  M84 X Y E\n\n  {action_respond_info(\"Print complete!\")}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PAUSE / RESUME / CANCEL\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro PAUSE]\ndescription: Pause the print and park the toolhead\nrename_existing: PAUSE_BASE\nvariable_park_x: 10\nvariable_park_y: 10\nvariable_park_z_lift: 10\nvariable_extrude: 1.0\ngcode:\n  {% set x      = params.X|default(printer['gcode_macro PAUSE'].park_x)|float %}\n  {% set y      = params.Y|default(printer['gcode_macro PAUSE'].park_y)|float %}\n  {% set z_lift = params.Z|default(printer['gcode_macro PAUSE'].park_z_lift)|float %}\n  {% set e      = printer['gcode_macro PAUSE'].extrude|float %}\n\n  SAVE_GCODE_STATE NAME=PAUSE_STATE\n  PAUSE_BASE\n\n  {% if printer.extruder.can_extrude %}\n    G91\n    G1 E-{e} F3600\n    G90\n  {% endif %}\n\n  {% set z_pos    = printer.toolhead.position.z %}\n  {% set z_target = [z_pos + z_lift, printer.toolhead.axis_maximum.z]|min %}\n  G90\n  G1 Z{z_target} F600\n  G1 X{x} Y{y} F12000\n\n[gcode_macro RESUME]\ndescription: Resume the print\nrename_existing: RESUME_BASE\nvariable_extrude: 1.0\ngcode:\n  {% set e = printer['gcode_macro RESUME'].extrude|float %}\n  {% if printer.extruder.can_extrude %}\n    G91\n    G1 E{e} F3600\n    G90\n  {% endif %}\n  RESTORE_GCODE_STATE NAME=PAUSE_STATE MOVE=1\n  RESUME_BASE\n\n[gcode_macro CANCEL_PRINT]\ndescription: Cancel the current print\nrename_existing: CANCEL_PRINT_BASE\ngcode:\n  CANCEL_PRINT_BASE\n  END_PRINT\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PID CALIBRATION\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro PID_HOTEND]\ndescription: PID calibration for the hotend. Usage: PID_HOTEND TEMP=220\ngcode:\n  {% set temp = params.TEMP|default(220)|float %}\n  {action_respond_info(\"Starting hotend PID calibration at %.0f\u00b0C...\" % temp)}\n  {action_respond_info(\"This will take several minutes. Do not interrupt.\")}\n  PID_CALIBRATE HEATER=extruder TARGET={temp}\n  SAVE_CONFIG\n  {action_respond_info(\"Hotend PID calibration complete. Config saved.\")}\n\n[gcode_macro PID_BED]\ndescription: PID calibration for the heated bed. Usage: PID_BED TEMP=60\ngcode:\n  {% set temp = params.TEMP|default(60)|float %}\n  {action_respond_info(\"Starting bed PID calibration at %.0f\u00b0C...\" % temp)}\n  {action_respond_info(\"This will take several minutes. Do not interrupt.\")}\n  PID_CALIBRATE HEATER=heater_bed TARGET={temp}\n  SAVE_CONFIG\n  {action_respond_info(\"Bed PID calibration complete. Config saved.\")}\n\n[gcode_macro PID_CHAMBER]\ndescription: Tune the chamber heater watermark. Usage: PID_CHAMBER TEMP=45\ngcode:\n  {% set temp = params.TEMP|default(45)|float %}\n  {action_respond_info(\"Heating chamber to %.0f\u00b0C for thermal soak observation...\" % temp)}\n  SET_HEATER_TEMPERATURE HEATER=chamber_heater TARGET={temp}\n  TEMPERATURE_WAIT SENSOR=\"heater_generic chamber_heater\" MINIMUM={temp - 2}\n  {action_respond_info(\"Chamber reached %.0f\u00b0C. Note: chamber_heater uses watermark control, not PID.\" % temp)}\n  {action_respond_info(\"Adjust max_delta in printer.cfg [verify_heater chamber_heater] if needed.\")}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# BED LEVELING\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro BED_LEVELING]\ndescription: Full bed leveling sequence with Z-tilt and mesh. Usage: BED_LEVELING BED_TEMP=60 EXTRUDER_TEMP=150\ngcode:\n  {% set bed_temp      = params.BED_TEMP|default(60)|float %}\n  {% set extruder_temp = params.EXTRUDER_TEMP|default(150)|float %}\n\n  {action_respond_info(\"Starting bed leveling sequence...\")}\n  {action_respond_info(\"Bed: %.0f\u00b0C  Nozzle: %.0f\u00b0C\" % (bed_temp, extruder_temp))}\n\n  G28\n  M140 S{bed_temp}\n  M109 S{extruder_temp}\n  M190 S{bed_temp}\n\n  {action_respond_info(\"Running Z-tilt adjustment...\")}\n  Z_TILT_ADJUST\n\n  {action_respond_info(\"Running full 9x9 bed mesh...\")}\n  BED_MESH_CALIBRATE PROFILE=default\n\n  SAVE_CONFIG\n  {action_respond_info(\"Bed leveling complete. Mesh saved as 'default'.\")}\n\n[gcode_macro Z_TILT_CALIBRATE]\ndescription: Run Z-tilt adjustment only (no bed mesh). Home first if needed.\ngcode:\n  {% if printer.toolhead.homed_axes != \"xyz\" %}\n    G28\n  {% endif %}\n  {action_respond_info(\"Running Z-tilt adjustment...\")}\n  Z_TILT_ADJUST\n  {action_respond_info(\"Z-tilt complete.\")}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# WARMUP (movement stress test \u2014 adapted from K1 for CoreXY / K2 Plus)\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro WARMUP]\ndescription: Movement warm-up to seat bearings and rods. Usage: WARMUP LOOPS=10 ACCEL=5000\nvariable_start_x: 5\nvariable_start_y: 5\nvariable_end_x: 345\nvariable_end_y: 345\ngcode:\n  {% set loops = params.LOOPS|default(10)|int %}\n  {% set accel = params.ACCEL|default(5000)|int %}\n\n  {action_respond_info(\"Starting warmup: %d loops at %d mm/s\u00b2 acceleration\" % (loops, accel))}\n  {action_respond_info(\"This moves the toolhead across the full bed. Make sure it is clear.\")}\n\n  {% if printer.toolhead.homed_axes != \"xyz\" %}\n    G28\n  {% endif %}\n\n  ; Save current acceleration\n  {% set orig_accel = printer.toolhead.max_accel %}\n  SET_VELOCITY_LIMIT ACCEL={accel}\n\n  G90\n  G1 F12000\n\n  {% for i in range(loops) %}\n    G1 X{printer['gcode_macro WARMUP'].start_x} Y{printer['gcode_macro WARMUP'].start_y}\n    G1 X{printer['gcode_macro WARMUP'].end_x}   Y{printer['gcode_macro WARMUP'].start_y}\n    G1 X{printer['gcode_macro WARMUP'].end_x}   Y{printer['gcode_macro WARMUP'].end_y}\n    G1 X{printer['gcode_macro WARMUP'].start_x} Y{printer['gcode_macro WARMUP'].end_y}\n    G1 X{printer['gcode_macro WARMUP'].start_x} Y{printer['gcode_macro WARMUP'].start_y}\n    G1 X{printer['gcode_macro WARMUP'].end_x}   Y{printer['gcode_macro WARMUP'].end_y}\n    G1 X{printer['gcode_macro WARMUP'].start_x} Y{printer['gcode_macro WARMUP'].end_y}\n    G1 X{printer['gcode_macro WARMUP'].end_x}   Y{printer['gcode_macro WARMUP'].start_y}\n  {% endfor %}\n\n  ; Restore original acceleration\n  SET_VELOCITY_LIMIT ACCEL={orig_accel}\n\n  G1 X{(printer['gcode_macro WARMUP'].end_x / 2)|int} Y{(printer['gcode_macro WARMUP'].end_y / 2)|int}\n  {action_respond_info(\"Warmup complete. %d loops done.\" % loops)}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# CHAMBER CONTROL\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro CHAMBER_HEAT]\ndescription: Set chamber heater target. Use WAIT=1 to wait for temp. Usage: CHAMBER_HEAT TARGET=45 WAIT=1\ngcode:\n  {% set target = params.TARGET|default(0)|float %}\n  {% set wait   = params.WAIT|default(0)|int %}\n  SET_HEATER_TEMPERATURE HEATER=chamber_heater TARGET={target}\n  {% if wait == 1 and target > 0 %}\n    {action_respond_info(\"Waiting for chamber to reach %.0f\u00b0C...\" % target)}\n    TEMPERATURE_WAIT SENSOR=\"heater_generic chamber_heater\" MINIMUM={target - 3}\n    {action_respond_info(\"Chamber reached target: %.0f\u00b0C\" % target)}\n  {% endif %}\n\n[gcode_macro CHAMBER_COOL]\ndescription: Disable chamber heater and run cooling fan at full speed\ngcode:\n  SET_HEATER_TEMPERATURE HEATER=chamber_heater TARGET=0\n  SET_TEMPERATURE_FAN_TARGET TEMPERATURE_FAN=chamber_fan TARGET=20\n  {action_respond_info(\"Chamber cooling: heater off, cooling fan running.\")}\n\n[gcode_macro CHAMBER_STATUS]\ndescription: Print current chamber temperature and target\ngcode:\n  {% set temp   = printer['heater_generic chamber_heater'].temperature %}\n  {% set target = printer['heater_generic chamber_heater'].target %}\n  {action_respond_info(\"Chamber: %.1f\u00b0C  /  target: %.1f\u00b0C\" % (temp, target))}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# BACKUP & RESTORE (from Fluidd/Mainsail console)\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro KLIPPER_BACKUP_CONFIG]\ndescription: Back up Klipper config files to backup_config.tar.gz in config folder\ngcode:\n  {action_respond_info(\"Backing up Klipper configuration...\")}\n  RUN_SHELL_COMMAND CMD=klipper_backup_config\n  {action_respond_info(\"Backup saved as backup_config.tar.gz in your config folder.\")}\n\n[gcode_macro KLIPPER_RESTORE_CONFIG]\ndescription: Restore Klipper config from backup_config.tar.gz \u2014 CAUTION: overwrites current config\ngcode:\n  {action_respond_info(\"Restoring Klipper configuration from backup_config.tar.gz...\")}\n  RUN_SHELL_COMMAND CMD=klipper_restore_config\n  {action_respond_info(\"Config restored. Restarting Klipper...\")}\n  FIRMWARE_RESTART\n\n[gcode_macro MOONRAKER_BACKUP_DATABASE]\ndescription: Back up Moonraker database to backup_database.tar.gz in config folder\ngcode:\n  {action_respond_info(\"Backing up Moonraker database...\")}\n  RUN_SHELL_COMMAND CMD=moonraker_backup_database\n  {action_respond_info(\"Moonraker database backup complete.\")}\n\n[gcode_macro MOONRAKER_RESTORE_DATABASE]\ndescription: Restore Moonraker database from backup_database.tar.gz\ngcode:\n  {action_respond_info(\"Restoring Moonraker database...\")}\n  RUN_SHELL_COMMAND CMD=moonraker_restore_database\n  {action_respond_info(\"Database restored.\")}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# CAMERA\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro RELOAD_CAMERA]\ndescription: Restart the WebRTC camera service without rebooting\ngcode:\n  {action_respond_info(\"Restarting camera service...\")}\n  RUN_SHELL_COMMAND CMD=restart_camera\n  {action_respond_info(\"Camera service restarted.\")}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# SLICER INTEGRATION HELPERS\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro SET_PRINT_STATS_INFO]\nrename_existing: SET_PRINT_STATS_INFO_BASE\ndescription: Update print stats with layer info from slicer\ngcode:\n  {% if params.TOTAL_LAYER is defined %}\n    SET_PRINT_STATS_INFO_BASE TOTAL_LAYER={params.TOTAL_LAYER}\n  {% endif %}\n  {% if params.CURRENT_LAYER is defined %}\n    SET_PRINT_STATS_INFO_BASE CURRENT_LAYER={params.CURRENT_LAYER}\n  {% endif %}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# Z-OFFSET\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\n[gcode_macro SAVE_Z_OFFSET]\ndescription: Save current live Z offset to printer.cfg\ngcode:\n  Z_OFFSET_APPLY_PROBE\n  SAVE_CONFIG\n\n[gcode_macro SET_Z_OFFSET]\ndescription: Apply a Z offset value and optionally save. Usage: SET_Z_OFFSET Z=0.05 SAVE=1\ngcode:\n  {% set z    = params.Z|default(0)|float %}\n  {% set save = params.SAVE|default(0)|int %}\n  SET_GCODE_OFFSET Z={z} MOVE=1\n  {action_respond_info(\"Z offset set to %.3fmm\" % z)}\n  {% if save == 1 %}\n    SAVE_Z_OFFSET\n  {% endif %}\n\nEOF\n\n    # Add gcode_shell_command entries (requires Klipper Gcode Shell Command)\n    cat >> \"$MACROS_CFG\" << 'EOF'\n# \u2500\u2500\u2500 Shell commands (used by backup/restore/camera macros) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# These require the Klipper Gcode Shell Command feature.\n# If not installed, the backup/restore/camera macros will not work.\n\n[gcode_shell_command restart_camera]\ncommand: /etc/rc.d/S97webrtc restart\ntimeout: 10.0\nverbose: False\n\n[gcode_shell_command klipper_backup_config]\ncommand: tar -czf /mnt/UDISK/printer_data/config/backup_config.tar.gz -C /mnt/UDISK/printer_data config/\ntimeout: 30.0\nverbose: True\n\n[gcode_shell_command klipper_restore_config]\ncommand: tar -xzf /mnt/UDISK/printer_data/config/backup_config.tar.gz -C /mnt/UDISK/printer_data/\ntimeout: 30.0\nverbose: True\n\n[gcode_shell_command moonraker_backup_database]\ncommand: tar -czf /mnt/UDISK/printer_data/config/backup_database.tar.gz -C /mnt/UDISK/printer_data database/\ntimeout: 30.0\nverbose: True\n\n[gcode_shell_command moonraker_restore_database]\ncommand: tar -xzf /mnt/UDISK/printer_data/config/backup_database.tar.gz -C /mnt/UDISK/printer_data/\ntimeout: 30.0\nverbose: True\nEOF\n\n    add_include_to_printer_cfg \"useful_macros.cfg\"\n    restart_klipper\n\n    mark_installed \"useful_macros\"\n    echo \"\"\n    log_success \"Useful Macros installed!\"\n    echo \"\"\n    echo \"  Available macros:\"\n    echo -e \"  ${GREEN}Print:${NC}        START_PRINT, END_PRINT, PAUSE, RESUME, CANCEL_PRINT\"\n    echo -e \"  ${GREEN}PID:${NC}          PID_HOTEND, PID_BED, PID_CHAMBER\"\n    echo -e \"  ${GREEN}Leveling:${NC}     BED_LEVELING, Z_TILT_CALIBRATE\"\n    echo -e \"  ${GREEN}Warmup:${NC}       WARMUP [LOOPS=10] [ACCEL=5000]\"\n    echo -e \"  ${GREEN}Chamber:${NC}      CHAMBER_HEAT, CHAMBER_COOL, CHAMBER_STATUS\"\n    echo -e \"  ${GREEN}Z-Offset:${NC}     SAVE_Z_OFFSET, SET_Z_OFFSET\"\n    echo -e \"  ${GREEN}Backup:${NC}       KLIPPER_BACKUP_CONFIG, KLIPPER_RESTORE_CONFIG\"\n    echo \"                MOONRAKER_BACKUP_DATABASE, MOONRAKER_RESTORE_DATABASE\"\n    echo -e \"  ${GREEN}Camera:${NC}       RELOAD_CAMERA\"\n    echo \"\"\n    log_info \"Slicer start G-code:\"\n    echo \"  START_PRINT BED_TEMP=[bed_temperature_initial_layer_single] EXTRUDER_TEMP=[nozzle_temperature_initial_layer] CHAMBER_TEMP=[chamber_temperature]\"\n    log_info \"Slicer end G-code:\"\n    echo \"  END_PRINT\"\n    echo \"\"\n}\n\nremove_useful_macros() {\n    echo \"\"\n    log_info \"Removing Useful Macros...\"\n    remove_include_from_printer_cfg \"useful_macros.cfg\"\n    rm -f \"$MACROS_CFG\"\n    restart_klipper\n    mark_removed \"useful_macros\"\n    log_success \"Useful Macros removed.\"\n    echo \"\"\n}\n\ncase \"$1\" in\n    install) install_useful_macros ;;\n    remove)  remove_useful_macros ;;\n    *)       echo \"Usage: $0 [install|remove]\" ;;\nesac\n")
print("  OK scripts/useful_macros.sh")

open("scripts/kamp.sh", "w").write("#!/bin/sh\n# kamp.sh - Install/remove Klipper Adaptive Meshing & Purging for K2 Plus\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\nKAMP_DIR=$CONFIG_DIR/KAMP\nKAMP_URL=https://github.com/kyleisah/Klipper-Adaptive-Meshing-Purging/archive/refs/heads/main.zip\n\ninstall_kamp() {\n    echo \"\"\n    log_info \"Installing Klipper Adaptive Meshing & Purging (KAMP)...\"\n    echo \"\"\n\n    if ! is_installed \"moonraker_extensions\"; then\n        log_warn \"Moonraker Extensions not installed. Installing now (required for KAMP)...\"\n        sh \"$SCRIPT_DIR/scripts/moonraker.sh\" install\n    fi\n\n    mkdir -p \"$KAMP_DIR\"\n\n    log_info \"Downloading KAMP...\"\n    python3 << 'PYEOF'\nimport urllib.request, zipfile, os, shutil, glob\nprint('Downloading KAMP...')\nurllib.request.urlretrieve(\n    'https://github.com/kyleisah/Klipper-Adaptive-Meshing-Purging/archive/refs/heads/main.zip',\n    '/tmp/kamp.zip'\n)\nprint('Extracting...')\nwith zipfile.ZipFile('/tmp/kamp.zip', 'r') as z:\n    z.extractall('/tmp/kamp_extract/')\nsrc = '/tmp/kamp_extract/Klipper-Adaptive-Meshing-Purging-main/Configuration/'\nimport os\nos.makedirs('/mnt/UDISK/printer_data/config/KAMP', exist_ok=True)\nfor f in glob.glob(src + '*.cfg'):\n    shutil.copy(f, '/mnt/UDISK/printer_data/config/KAMP/')\n    print('Copied: ' + os.path.basename(f))\nimport shutil as sh\nsh.rmtree('/tmp/kamp_extract', ignore_errors=True)\nos.remove('/tmp/kamp.zip')\nprint('Done')\nPYEOF\n\n    # Write KAMP_Settings.cfg tuned for K2 Plus 350x350 bed\n    cat > \"$KAMP_DIR/KAMP_Settings.cfg\" << 'EOF'\n# KAMP Settings \u2014 K2 Plus (350x350mm bed)\n[include ./Adaptive_Meshing.cfg]\n[include ./Line_Purge.cfg]\n\n[gcode_macro _KAMP_Settings]\nvariable_verbose_enable: True\nvariable_mesh_margin: 5\nvariable_fuzz_amount: 0\nvariable_probe_dock_enable: False\nvariable_attach_macro: 'Attach_Probe'\nvariable_detach_macro: 'Dock_Probe'\nvariable_purge_height: 0.8\nvariable_tip_distance: 3\nvariable_purge_margin: 10\nvariable_purge_amount: 30\nvariable_flow_rate: 12\nvariable_start_x: 10\nvariable_start_y: 10\nvariable_size: 15\nvariable_smart_park_height: 5\ngcode:\nEOF\n\n    add_include_to_printer_cfg \"KAMP/KAMP_Settings.cfg\"\n\n    # Ensure object processing is enabled in moonraker.conf\n    if [ -f \"$CONFIG_DIR/moonraker.conf\" ]; then\n        if ! grep -q \"enable_object_processing: True\" \"$CONFIG_DIR/moonraker.conf\"; then\n            echo \"\" >> \"$CONFIG_DIR/moonraker.conf\"\n            echo \"[file_manager]\" >> \"$CONFIG_DIR/moonraker.conf\"\n            echo \"enable_object_processing: True\" >> \"$CONFIG_DIR/moonraker.conf\"\n            restart_moonraker\n        fi\n    fi\n\n    restart_klipper\n    mark_installed \"kamp\"\n    echo \"\"\n    log_success \"KAMP installed!\"\n    log_info \"Add BED_MESH_CALIBRATE to your START_PRINT macro.\"\n    log_info \"Add LINE_PURGE after heating for a purge line at the print edge.\"\n    echo \"\"\n}\n\nremove_kamp() {\n    echo \"\"\n    log_info \"Removing KAMP...\"\n    remove_include_from_printer_cfg \"KAMP/KAMP_Settings.cfg\"\n    rm -rf \"$KAMP_DIR\"\n    restart_klipper\n    mark_removed \"kamp\"\n    log_success \"KAMP removed.\"\n    echo \"\"\n}\n\ncase \"$1\" in\n    install) install_kamp ;;\n    remove)  remove_kamp ;;\n    *)       echo \"Usage: $0 [install|remove]\" ;;\nesac\n")
print("  OK scripts/kamp.sh")

open("scripts/mainsail.sh", "w").write("#!/bin/sh\n# mainsail.sh - Install, update, repair, or remove Mainsail on port 4409 for K2 Plus\n\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\n\nMAINSAIL_DIR=/usr/share/mainsail\nMAINSAIL_URL=https://github.com/mainsail-crew/mainsail/releases/latest/download/mainsail.zip\nNGINX_CONF=/etc/nginx/nginx.conf\n\n# \u2500\u2500 Download helper \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ncheck_download_tool() {\n    if which wget > /dev/null 2>&1; then\n        DOWNLOAD_CMD=\"wget\"\n    elif which curl > /dev/null 2>&1; then\n        DOWNLOAD_CMD=\"curl\"\n    else\n        log_error \"Neither wget nor curl found. Install Entware first.\"\n        return 1\n    fi\n}\n\ndownload_file() {\n    local url=\"$1\"\n    local dest=\"$2\"\n    if [ \"$DOWNLOAD_CMD\" = \"wget\" ]; then\n        wget -q --show-progress -O \"$dest\" \"$url\"\n    else\n        curl -L --progress-bar -o \"$dest\" \"$url\"\n    fi\n}\n\n# \u2500\u2500 Nginx block management \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ncheck_mainsail_nginx_block() {\n    grep -q \"listen 4409\" \"$NGINX_CONF\" 2>/dev/null\n}\n\nrestore_mainsail_nginx_block() {\n    if check_mainsail_nginx_block; then\n        log_info \"Mainsail nginx block (port 4409) already present.\"\n        return 0\n    fi\n\n    log_info \"Adding Mainsail nginx block on port 4409...\"\n    backup_nginx_conf\n\n    python3 - << PYEOF\nwith open('$NGINX_CONF') as f:\n    content = f.read()\n\nmainsail_block = \"\"\"\n    server {\n        listen 4409 default_server;\n\n        access_log /var/log/nginx/mainsail-access.log;\n        error_log /var/log/nginx/mainsail-error.log;\n\n        gzip on;\n        gzip_vary on;\n        gzip_proxied any;\n        gzip_comp_level 4;\n        gzip_buffers 16 8k;\n        gzip_http_version 1.1;\n        gzip_types text/plain text/css text/xml text/javascript application/x-javascript application/json application/xml;\n\n        root /usr/share/mainsail;\n        index index.html;\n        server_name _;\n        client_max_body_size 0;\n        proxy_request_buffering off;\n\n        location / {\n            try_files \\$uri \\$uri/ /index.html;\n        }\n        location = /index.html {\n            add_header Cache-Control \"no-store, no-cache, must-revalidate\";\n        }\n        location /websocket {\n            proxy_pass http://apiserver/websocket;\n            proxy_http_version 1.1;\n            proxy_set_header Upgrade \\$http_upgrade;\n            proxy_set_header Connection \\$connection_upgrade;\n            proxy_set_header Host \\$http_host;\n            proxy_set_header X-Real-IP \\$remote_addr;\n            proxy_set_header X-Forwarded-For \\$proxy_add_x_forwarded_for;\n            proxy_read_timeout 86400;\n        }\n        location ~ ^/(printer|api|access|machine|server)/ {\n            proxy_pass http://apiserver\\$request_uri;\n            proxy_set_header Host \\$http_host;\n            proxy_set_header X-Real-IP \\$remote_addr;\n            proxy_set_header X-Forwarded-For \\$proxy_add_x_forwarded_for;\n            proxy_set_header X-Scheme \\$scheme;\n        }\n        location /webcam/  { proxy_pass http://mjpgstreamer1/; }\n        location /webcam2/ { proxy_pass http://mjpgstreamer2/; }\n        location /webcam3/ { proxy_pass http://mjpgstreamer3/; }\n        location /webcam4/ { proxy_pass http://mjpgstreamer4/; }\n    }\n\"\"\"\n\ncontent = content.rstrip()\nif content.endswith('}'):\n    content = content[:-1] + mainsail_block + '\\n}'\n\nwith open('$NGINX_CONF', 'w') as f:\n    f.write(content)\nprint(\"Mainsail nginx block added on port 4409.\")\nPYEOF\n\n    restart_nginx\n    log_success \"Mainsail nginx block restored on port 4409.\"\n}\n\nremove_mainsail_nginx_block() {\n    if ! check_mainsail_nginx_block; then\n        log_info \"Mainsail nginx block not found \u2014 nothing to remove.\"\n        return 0\n    fi\n\n    log_info \"Removing Mainsail nginx block from nginx.conf...\"\n    python3 - << PYEOF\nimport re\nwith open('$NGINX_CONF') as f:\n    content = f.read()\n# Remove the server block listening on 4409\ncontent = re.sub(r'\\n\\s*server\\s*\\{[^}]*listen\\s+4409[^}]*(?:\\{[^}]*\\}[^}]*)?\\}', '', content)\nwith open('$NGINX_CONF', 'w') as f:\n    f.write(content)\nprint(\"Mainsail nginx block removed.\")\nPYEOF\n    log_success \"Mainsail nginx block removed.\"\n}\n\n# \u2500\u2500 Status \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nstatus_mainsail() {\n    echo \"\"\n    echo \"Mainsail status:\"\n    if [ -f \"$MAINSAIL_DIR/index.html\" ]; then\n        log_success \"Static files present at $MAINSAIL_DIR\"\n        if [ -f \"$MAINSAIL_DIR/version\" ]; then\n            echo \"  Version: $(cat $MAINSAIL_DIR/version)\"\n        fi\n    else\n        log_warn \"Static files NOT found at $MAINSAIL_DIR\"\n    fi\n\n    if check_mainsail_nginx_block; then\n        log_success \"Nginx block present (port 4409)\"\n    else\n        log_warn \"Nginx block NOT found for port 4409\"\n    fi\n\n    if pgrep -f nginx > /dev/null; then\n        log_success \"Nginx is running\"\n    else\n        log_warn \"Nginx is NOT running\"\n    fi\n    echo \"\"\n}\n\n# \u2500\u2500 Install / update / repair \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ninstall_mainsail() {\n    echo \"\"\n\n    # Detect whether this is a fresh install or update/repair\n    if [ -d \"$MAINSAIL_DIR\" ] && [ -f \"$MAINSAIL_DIR/index.html\" ]; then\n        echo -e \"${YELLOW}Mainsail is already installed at $MAINSAIL_DIR.${NC}\"\n        if [ -f \"$MAINSAIL_DIR/version\" ]; then\n            echo \"  Current version: $(cat $MAINSAIL_DIR/version)\"\n        fi\n        echo \"\"\n        echo \"  1) Update to the latest version\"\n        echo \"  2) Repair (re-download and reinstall)\"\n        echo \"  3) Restore nginx block only (if port 4409 is broken)\"\n        echo \"  0) Cancel\"\n        echo \"\"\n        printf \"  Enter choice: \"\n        read subchoice\n        case \"$subchoice\" in\n            1|2) : ;;  # continue with full install\n            3)  restore_mainsail_nginx_block; return 0 ;;\n            *)  log_info \"Cancelled.\"; return 0 ;;\n        esac\n    else\n        log_info \"Installing Mainsail...\"\n    fi\n\n    echo \"\"\n    log_info \"Downloading latest Mainsail...\"\n    python3 << PYEOF || { log_error \"Download failed. Check your internet connection.\"; return 1; }\nimport urllib.request, zipfile, os\nos.makedirs('$MAINSAIL_DIR', exist_ok=True)\nprint('Downloading Mainsail...')\nurllib.request.urlretrieve('$MAINSAIL_URL', '/tmp/mainsail.zip')\nprint('Extracting...')\nwith zipfile.ZipFile('/tmp/mainsail.zip', 'r') as z:\n    z.extractall('$MAINSAIL_DIR')\nos.remove('/tmp/mainsail.zip')\nprint('Done')\nPYEOF\n\n    if [ ! -f \"$MAINSAIL_DIR/index.html\" ]; then\n        log_error \"Installation failed \u2014 index.html not found after extraction.\"\n        return 1\n    fi\n\n    # Ensure nginx block is in place\n    restore_mainsail_nginx_block\n\n    restart_nginx\n\n    if [ -f \"$MAINSAIL_DIR/version\" ]; then\n        NEW_VER=$(cat \"$MAINSAIL_DIR/version\")\n        log_success \"Mainsail installed: version $NEW_VER\"\n    else\n        log_success \"Mainsail installed successfully.\"\n    fi\n\n    mark_installed \"mainsail\"\n    echo \"\"\n    log_info \"Access Mainsail at: http://$(hostname -I | awk '{print $1}'):4409\"\n    echo \"\"\n}\n\n# \u2500\u2500 Remove \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nremove_mainsail() {\n    echo \"\"\n    echo -e \"${YELLOW}WARNING: This removes Mainsail static files and the port 4409 nginx block.${NC}\"\n    echo \"Fluidd on port 4408 is not affected.\"\n    echo \"\"\n    printf \"Are you sure? [y/N]: \"\n    read confirm\n    if [ \"$confirm\" != \"y\" ] && [ \"$confirm\" != \"Y\" ]; then\n        log_info \"Cancelled.\"\n        return 0\n    fi\n\n    remove_mainsail_nginx_block\n    rm -rf \"$MAINSAIL_DIR\"\n    restart_nginx\n    mark_removed \"mainsail\"\n    echo \"\"\n    log_success \"Mainsail removed.\"\n    log_info \"Fluidd on port 4408 is unaffected.\"\n    echo \"\"\n}\n\n# \u2500\u2500 Entry point \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ncase \"$1\" in\n    install) install_mainsail ;;\n    remove)  remove_mainsail ;;\n    restore) restore_mainsail_nginx_block; restart_nginx ;;\n    status)  status_mainsail ;;\n    *)       echo \"Usage: $0 [install|remove|restore|status]\" ;;\nesac\n")
print("  OK scripts/mainsail.sh")

open("scripts/fluidd.sh", "w").write("#!/bin/sh\n# fluidd.sh - Install, repair, or remove Fluidd for K2 Plus\n#\n# The K2 Plus ships with Fluidd pre-installed at /usr/share/fluidd served on port 4408.\n# This script can:\n#   install  - download and install the latest Fluidd (replaces stock or broken install)\n#   remove   - remove Fluidd static files (nginx block stays, port 4408 will 404)\n#   restore  - restore the nginx config to serve Fluidd on port 4408\n\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\n\nFLUIDD_DIR=/usr/share/fluidd\nFLUIDD_URL=https://github.com/fluidd-core/fluidd/releases/latest/download/fluidd.zip\nNGINX_CONF=/etc/nginx/nginx.conf\n\n# Stock nginx server block for Fluidd \u2014 matches what ships on the K2 Plus\nSTOCK_FLUIDD_BLOCK='    server {\n        listen 4408 default_server;\n\n        access_log /var/log/nginx/fluidd-access.log;\n        error_log /var/log/nginx/fluidd-error.log;\n\n        gzip on;\n        gzip_vary on;\n        gzip_proxied any;\n        gzip_proxied expired no-cache no-store private auth;\n        gzip_comp_level 4;\n        gzip_buffers 16 8k;\n        gzip_http_version 1.1;\n        gzip_types text/plain text/css text/xml text/javascript application/x-javascript application/json application/xml;\n\n        root /usr/share/fluidd;\n        index index.html;\n        server_name _;\n        client_max_body_size 0;\n        proxy_request_buffering off;\n\n        location / {\n            try_files $uri $uri/ /index.html;\n        }\n        location = /index.html {\n            add_header Cache-Control \"no-store, no-cache, must-revalidate\";\n        }\n        location /websocket {\n            proxy_pass http://apiserver/websocket;\n            proxy_http_version 1.1;\n            proxy_set_header Upgrade $http_upgrade;\n            proxy_set_header Connection $connection_upgrade;\n            proxy_set_header Host $http_host;\n            proxy_set_header X-Real-IP $remote_addr;\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n            proxy_read_timeout 86400;\n        }\n        location ~ ^/(printer|api|access|machine|server)/ {\n            proxy_pass http://apiserver$request_uri;\n            proxy_set_header Host $http_host;\n            proxy_set_header X-Real-IP $remote_addr;\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n            proxy_set_header X-Scheme $scheme;\n        }\n        location /webcam/  { proxy_pass http://mjpgstreamer1/; }\n        location /webcam2/ { proxy_pass http://mjpgstreamer2/; }\n        location /webcam3/ { proxy_pass http://mjpgstreamer3/; }\n        location /webcam4/ { proxy_pass http://mjpgstreamer4/; }\n    }'\n\n# \u2500\u2500 Check internet \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ncheck_download_tool() {\n    if which wget > /dev/null 2>&1; then\n        DOWNLOAD_CMD=\"wget\"\n    elif which curl > /dev/null 2>&1; then\n        DOWNLOAD_CMD=\"curl\"\n    else\n        log_error \"Neither wget nor curl found. Install Entware first or check your PATH.\"\n        return 1\n    fi\n}\n\ndownload_file() {\n    local url=\"$1\"\n    local dest=\"$2\"\n    if [ \"$DOWNLOAD_CMD\" = \"wget\" ]; then\n        wget -q --show-progress -O \"$dest\" \"$url\"\n    else\n        curl -L --progress-bar -o \"$dest\" \"$url\"\n    fi\n}\n\n# \u2500\u2500 Nginx: check and restore Fluidd block \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ncheck_fluidd_nginx_block() {\n    grep -q \"listen 4408\" \"$NGINX_CONF\" 2>/dev/null\n}\n\nrestore_fluidd_nginx_block() {\n    if check_fluidd_nginx_block; then\n        log_info \"Fluidd nginx block (port 4408) already present.\"\n        return 0\n    fi\n\n    log_info \"Adding Fluidd nginx block on port 4408...\"\n    backup_nginx_conf\n\n    python3 - << PYEOF\nwith open('$NGINX_CONF') as f:\n    content = f.read()\n\nfluidd_block = \"\"\"\n$STOCK_FLUIDD_BLOCK\n\"\"\"\n\n# Insert before the closing brace of the http block\ncontent = content.rstrip()\nif content.endswith('}'):\n    content = content[:-1] + fluidd_block + '\\n}'\n\nwith open('$NGINX_CONF', 'w') as f:\n    f.write(content)\nprint(\"Fluidd nginx block restored on port 4408.\")\nPYEOF\n\n    restart_nginx\n}\n\n# \u2500\u2500 Install / repair Fluidd \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ninstall_fluidd() {\n    echo \"\"\n\n    # Detect whether this is a fresh install or a repair\n    if [ -d \"$FLUIDD_DIR\" ] && [ -f \"$FLUIDD_DIR/index.html\" ]; then\n        echo -e \"${YELLOW}Fluidd is already installed at $FLUIDD_DIR.${NC}\"\n        echo \"\"\n        echo \"  1) Update to the latest version\"\n        echo \"  2) Repair (re-download and reinstall current latest)\"\n        echo \"  0) Cancel\"\n        echo \"\"\n        printf \"  Enter choice: \"\n        read subchoice\n        case \"$subchoice\" in\n            1|2) : ;;  # continue with install\n            *)  log_info \"Cancelled.\"; return 0 ;;\n        esac\n    else\n        log_info \"Installing Fluidd...\"\n    fi\n\n    echo \"\"\n    check_download_tool || return 1\n\n    # Get current installed version if present\n    if [ -f \"$FLUIDD_DIR/version\" ]; then\n        CURRENT_VER=$(cat \"$FLUIDD_DIR/version\")\n        log_info \"Current version: $CURRENT_VER\"\n    fi\n\n    log_info \"Downloading latest Fluidd...\"\n    download_file \"$FLUIDD_URL\" /tmp/fluidd.zip\n\n    if [ ! -f /tmp/fluidd.zip ] || [ ! -s /tmp/fluidd.zip ]; then\n        log_error \"Download failed. Check your internet connection.\"\n        rm -f /tmp/fluidd.zip\n        return 1\n    fi\n\n    log_info \"Installing Fluidd to $FLUIDD_DIR...\"\n    mkdir -p \"$FLUIDD_DIR\"\n    unzip -q -o /tmp/fluidd.zip -d \"$FLUIDD_DIR\"\n    rm -f /tmp/fluidd.zip\n\n    if [ ! -f \"$FLUIDD_DIR/index.html\" ]; then\n        log_error \"Installation failed \u2014 index.html not found after extraction.\"\n        return 1\n    fi\n\n    # Ensure nginx block is in place\n    restore_fluidd_nginx_block\n\n    # Restart nginx to serve updated files\n    restart_nginx\n\n    # Show installed version\n    if [ -f \"$FLUIDD_DIR/version\" ]; then\n        NEW_VER=$(cat \"$FLUIDD_DIR/version\")\n        log_success \"Fluidd installed: version $NEW_VER\"\n    else\n        log_success \"Fluidd installed successfully.\"\n    fi\n\n    mark_installed \"fluidd_updated\"\n    echo \"\"\n    log_info \"Access Fluidd at: http://$(hostname -I | awk '{print $1}'):4408\"\n    echo \"\"\n}\n\n# \u2500\u2500 Remove Fluidd static files \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nremove_fluidd() {\n    echo \"\"\n    echo -e \"${YELLOW}WARNING: This removes the Fluidd web interface static files.${NC}\"\n    echo \"Port 4408 will return a 404 until Fluidd is reinstalled.\"\n    echo \"Moonraker and Klipper continue running normally.\"\n    echo \"\"\n    printf \"Are you sure? [y/N]: \"\n    read confirm\n    if [ \"$confirm\" != \"y\" ] && [ \"$confirm\" != \"Y\" ]; then\n        log_info \"Cancelled.\"\n        return 0\n    fi\n\n    log_info \"Removing Fluidd static files from $FLUIDD_DIR...\"\n    rm -rf \"$FLUIDD_DIR\"\n    mkdir -p \"$FLUIDD_DIR\"  # keep the directory so nginx doesn't error on root\n\n    restart_nginx\n    mark_removed \"fluidd_updated\"\n    echo \"\"\n    log_success \"Fluidd removed.\"\n    log_info \"To reinstall, run this script again and select Install.\"\n    echo \"\"\n}\n\n# \u2500\u2500 Status \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nstatus_fluidd() {\n    echo \"\"\n    echo \"Fluidd status:\"\n    if [ -f \"$FLUIDD_DIR/index.html\" ]; then\n        log_success \"Static files present at $FLUIDD_DIR\"\n        if [ -f \"$FLUIDD_DIR/version\" ]; then\n            echo \"  Version: $(cat $FLUIDD_DIR/version)\"\n        fi\n    else\n        log_warn \"Static files NOT found at $FLUIDD_DIR\"\n    fi\n\n    if check_fluidd_nginx_block; then\n        log_success \"Nginx block present (port 4408)\"\n    else\n        log_warn \"Nginx block NOT found for port 4408\"\n    fi\n\n    if pgrep -f nginx > /dev/null; then\n        log_success \"Nginx is running\"\n    else\n        log_warn \"Nginx is NOT running\"\n    fi\n    echo \"\"\n}\n\n# \u2500\u2500 Entry point \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ncase \"$1\" in\n    install) install_fluidd ;;\n    remove)  remove_fluidd ;;\n    restore) restore_fluidd_nginx_block; restart_nginx ;;\n    status)  status_fluidd ;;\n    *)       echo \"Usage: $0 [install|remove|restore|status]\" ;;\nesac\n")
print("  OK scripts/fluidd.sh")

open("scripts/timelapse.sh", "w").write("#!/bin/sh\n# timelapse.sh - Moonraker Timelapse for K2 Plus\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\nTIMELAPSE_URL=https://github.com/mainsail-crew/moonraker-timelapse/archive/refs/heads/main.zip\nTIMELAPSE_DIR=/mnt/UDISK/printer_data/timelapse\nTIMELAPSE_COMPONENT=/usr/share/moonraker/components/timelapse.py\n\ninstall_timelapse() {\n    echo \"\"\n    log_info \"Installing Moonraker Timelapse...\"\n    echo \"\"\n\n    if ! is_installed \"moonraker_extensions\"; then\n        log_warn \"Moonraker Extensions not installed. Installing now (required for timelapse)...\"\n        sh \"$SCRIPT_DIR/scripts/moonraker.sh\" install\n    fi\n\n    log_info \"Downloading moonraker-timelapse...\"\n    python3 << PYEOF || { log_error \"Download failed.\"; return 1; }\nimport urllib.request, zipfile, os\nos.makedirs('/tmp/timelapse_extract', exist_ok=True)\nprint('Downloading moonraker-timelapse...')\nurllib.request.urlretrieve('$TIMELAPSE_URL', '/tmp/timelapse.zip')\nprint('Extracting...')\nwith zipfile.ZipFile('/tmp/timelapse.zip', 'r') as z:\n    z.extractall('/tmp/timelapse_extract/')\nos.remove('/tmp/timelapse.zip')\nprint('Done')\nPYEOF\n\n    # Install the moonraker component\n    cp /tmp/timelapse_extract/moonraker-timelapse-main/component/timelapse.py \"$TIMELAPSE_COMPONENT\"\n\n    # Install the Klipper macro\n    cp /tmp/timelapse_extract/moonraker-timelapse-main/klipper_macro/timelapse.cfg \"$CONFIG_DIR/\"\n\n    rm -rf /tmp/timelapse.zip /tmp/timelapse_extract\n\n    # Create timelapse output directory\n    mkdir -p \"$TIMELAPSE_DIR\"\n\n    # Add moonraker section\n    add_moonraker_section \"timelapse\" \"[timelapse]\noutput_path: /mnt/UDISK/printer_data/timelapse/\nframe_path: /tmp/timelapse/\nffmpeg_binary_path: /usr/bin/ffmpeg\"\n\n    add_include_to_printer_cfg \"timelapse.cfg\"\n\n    restart_moonraker\n    restart_klipper\n\n    mark_installed \"moonraker_timelapse\"\n    echo \"\"\n    log_success \"Moonraker Timelapse installed!\"\n    log_info \"Add TIMELAPSE_TAKE_FRAME to your layer change G-code in the slicer.\"\n    log_info \"Add TIMELAPSE_RENDER to your end G-code.\"\n    log_info \"Videos saved to: /mnt/UDISK/printer_data/timelapse/\"\n    echo \"\"\n}\n\nremove_timelapse() {\n    echo \"\"\n    log_info \"Removing Moonraker Timelapse...\"\n    remove_moonraker_section \"timelapse\"\n    remove_include_from_printer_cfg \"timelapse.cfg\"\n    rm -f \"$TIMELAPSE_COMPONENT\"\n    rm -f \"$CONFIG_DIR/timelapse.cfg\"\n    restart_moonraker\n    restart_klipper\n    mark_removed \"moonraker_timelapse\"\n    log_success \"Moonraker Timelapse removed.\"\n    echo \"\"\n}\n\ncase \"$1\" in\n    install) install_timelapse ;;\n    remove)  remove_timelapse ;;\nesac\n")
print("  OK scripts/timelapse.sh")

open("scripts/system.sh", "w").write("#!/bin/sh\n# system.sh - Service management and system utilities for K2 Plus Helper Script\n\nSCRIPT_DIR=/mnt/UDISK/helper-script\nCONFIG_DIR=/mnt/UDISK/printer_data/config\nLOGS_DIR=/mnt/UDISK/printer_data/logs\nINSTALLED_FILE=$SCRIPT_DIR/.installed\n\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m'\n\nlog_info()    { echo -e \"${GREEN}[INFO]${NC} $1\"; }\nlog_warn()    { echo -e \"${YELLOW}[WARN]${NC} $1\"; }\nlog_error()   { echo -e \"${RED}[ERROR]${NC} $1\"; }\nlog_success() { echo -e \"${GREEN}[OK]${NC} $1\"; }\n\n# \u2500\u2500 Service restarts \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nrestart_klipper() {\n    log_info \"Restarting Klipper...\"\n    /etc/rc.d/S55klipper restart\n    sleep 3\n    if pgrep -f \"klippy.py\" > /dev/null; then\n        log_success \"Klipper restarted successfully.\"\n    else\n        log_error \"Klipper failed to restart. Check $LOGS_DIR/klippy.log\"\n    fi\n}\n\nrestart_moonraker() {\n    log_info \"Restarting Moonraker...\"\n    # Kill ALL running moonraker instances (stock + helper script)\n    for pid in $(ps aux | grep moonraker.py | grep -v grep | awk '{print $1}'); do\n        kill \"$pid\" 2>/dev/null\n    done\n    sleep 2\n    /etc/rc.d/S56moonraker start\n    sleep 3\n    if pgrep -f \"moonraker.py\" > /dev/null; then\n        log_success \"Moonraker restarted successfully.\"\n    else\n        log_error \"Moonraker failed to restart. Check $LOGS_DIR/moonraker.log\"\n    fi\n}\n\nrestart_nginx() {\n    log_info \"Restarting Nginx...\"\n    /etc/rc.d/S80nginx restart\n    sleep 2\n    if pgrep -f \"nginx\" > /dev/null; then\n        log_success \"Nginx restarted successfully.\"\n    else\n        log_error \"Nginx failed to restart.\"\n    fi\n}\n\nrestart_camera() {\n    log_info \"Restarting WebRTC camera service...\"\n    /etc/rc.d/S97webrtc restart\n    sleep 2\n    log_success \"Camera service restarted.\"\n}\n\n# \u2500\u2500 Feature tracking \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nmark_installed() {\n    local feature=\"$1\"\n    touch \"$INSTALLED_FILE\" 2>/dev/null\n    if ! grep -q \"^$feature$\" \"$INSTALLED_FILE\" 2>/dev/null; then\n        echo \"$feature\" >> \"$INSTALLED_FILE\"\n    fi\n}\n\nmark_removed() {\n    local feature=\"$1\"\n    if [ -f \"$INSTALLED_FILE\" ]; then\n        sed -i \"/^$feature$/d\" \"$INSTALLED_FILE\"\n    fi\n}\n\nis_installed() {\n    local feature=\"$1\"\n    [ -f \"$INSTALLED_FILE\" ] && grep -q \"^$feature$\" \"$INSTALLED_FILE\"\n}\n\nshow_installed() {\n    echo \"\"\n    echo \"Installed features:\"\n    if [ -f \"$INSTALLED_FILE\" ] && [ -s \"$INSTALLED_FILE\" ]; then\n        while IFS= read -r line; do\n            echo \"  ${GREEN}\u2713${NC} $line\"\n        done < \"$INSTALLED_FILE\"\n    else\n        echo \"  None installed yet.\"\n    fi\n    echo \"\"\n}\n\n# \u2500\u2500 printer.cfg include management \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n# Add an [include filename.cfg] line to printer.cfg if not already present\nadd_include_to_printer_cfg() {\n    local include_file=\"$1\"\n    local printer_cfg=\"$CONFIG_DIR/printer.cfg\"\n\n    if grep -q \"^\\[include ${include_file}\\]\" \"$printer_cfg\" 2>/dev/null; then\n        log_info \"[include ${include_file}] already present in printer.cfg\"\n        return 0\n    fi\n\n    # Insert after the last existing [include ...] line, or at top if none\n    if grep -q \"^\\[include \" \"$printer_cfg\"; then\n        # Find line number of last include and insert after it\n        last_include=$(grep -n \"^\\[include \" \"$printer_cfg\" | tail -1 | cut -d: -f1)\n        sed -i \"${last_include}a [include ${include_file}]\" \"$printer_cfg\"\n    else\n        # No includes yet - add after the first comment block\n        sed -i \"1s/^/[include ${include_file}]\\n/\" \"$printer_cfg\"\n    fi\n\n    log_success \"Added [include ${include_file}] to printer.cfg\"\n}\n\n# Remove an [include filename.cfg] line from printer.cfg\nremove_include_from_printer_cfg() {\n    local include_file=\"$1\"\n    local printer_cfg=\"$CONFIG_DIR/printer.cfg\"\n\n    if grep -q \"^\\[include ${include_file}\\]\" \"$printer_cfg\" 2>/dev/null; then\n        sed -i \"/^\\[include ${include_file}\\]$/d\" \"$printer_cfg\"\n        log_success \"Removed [include ${include_file}] from printer.cfg\"\n    fi\n}\n\n# \u2500\u2500 moonraker.conf management \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nMOONRAKER_CONF=$CONFIG_DIR/moonraker.conf\nMOONRAKER_RC=/etc/rc.d/S56moonraker\nMOONRAKER_STOCK_CONF=/usr/share/moonraker/moonraker.conf\n\n# Patch S56moonraker to use our config wrapper instead of the stock one\npatch_moonraker_startup() {\n    if grep -q \"CONF=/mnt/UDISK\" \"$MOONRAKER_RC\" 2>/dev/null; then\n        log_info \"Moonraker startup already patched.\"\n        return 0\n    fi\n\n    # Back up original\n    if [ ! -f \"${MOONRAKER_RC}.orig\" ]; then\n        cp \"$MOONRAKER_RC\" \"${MOONRAKER_RC}.orig\"\n        log_success \"Backed up original S56moonraker to ${MOONRAKER_RC}.orig\"\n    fi\n\n    # Replace the CONF= line\n    sed -i \"s|CONF=/usr/share/moonraker/moonraker.conf|CONF=/mnt/UDISK/printer_data/config/moonraker.conf|g\" \"$MOONRAKER_RC\"\n    log_success \"Patched S56moonraker to use /mnt/UDISK/printer_data/config/moonraker.conf\"\n}\n\n# Restore the original CONF= line\nunpatch_moonraker_startup() {\n    if [ -f \"${MOONRAKER_RC}.orig\" ]; then\n        cp \"${MOONRAKER_RC}.orig\" \"$MOONRAKER_RC\"\n        log_success \"Restored original S56moonraker startup.\"\n        rm -f \"${MOONRAKER_RC}.orig\"\n    else\n        # Restore manually if backup is missing\n        sed -i \"s|CONF=/mnt/UDISK/printer_data/config/moonraker.conf|CONF=/usr/share/moonraker/moonraker.conf|g\" \"$MOONRAKER_RC\"\n        log_success \"Restored S56moonraker CONF to stock path.\"\n    fi\n}\n\n# Add a section to our moonraker.conf (idempotent)\nadd_moonraker_section() {\n    local section_name=\"$1\"\n    local section_content=\"$2\"\n\n    if grep -q \"^\\[${section_name}\" \"$MOONRAKER_CONF\" 2>/dev/null; then\n        log_info \"[$section_name] already present in moonraker.conf\"\n        return 0\n    fi\n\n    echo \"\" >> \"$MOONRAKER_CONF\"\n    echo \"$section_content\" >> \"$MOONRAKER_CONF\"\n    log_success \"Added [$section_name] to moonraker.conf\"\n}\n\n# Remove a section from our moonraker.conf\nremove_moonraker_section() {\n    local section_name=\"$1\"\n    if [ ! -f \"$MOONRAKER_CONF\" ]; then return 0; fi\n\n    # Remove from [section_name] to the next blank line + section start\n    python3 - \"$MOONRAKER_CONF\" \"$section_name\" << 'PYEOF'\nimport sys, re\npath, section = sys.argv[1], sys.argv[2]\nwith open(path) as f:\n    content = f.read()\n# Remove the section block\npattern = r'\\n\\[' + re.escape(section) + r'\\][^\\[]*'\ncontent = re.sub(pattern, '', content)\nwith open(path, 'w') as f:\n    f.write(content)\nPYEOF\n    log_success \"Removed [$section_name] from moonraker.conf\"\n}\n\n# \u2500\u2500 nginx management \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nNGINX_CONF=/etc/nginx/nginx.conf\nNGINX_CONF_BAK=/mnt/UDISK/helper-script/.nginx.conf.bak\n\nbackup_nginx_conf() {\n    if [ ! -f \"$NGINX_CONF_BAK\" ]; then\n        cp \"$NGINX_CONF\" \"$NGINX_CONF_BAK\"\n        log_success \"Backed up nginx.conf to $NGINX_CONF_BAK\"\n    fi\n}\n\nrestore_nginx_conf() {\n    if [ -f \"$NGINX_CONF_BAK\" ]; then\n        cp \"$NGINX_CONF_BAK\" \"$NGINX_CONF\"\n        log_success \"Restored nginx.conf from backup.\"\n        rm -f \"$NGINX_CONF_BAK\"\n        restart_nginx\n    else\n        log_warn \"No nginx.conf backup found.\"\n    fi\n}\n\n# \u2500\u2500 Entry point \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ncase \"$1\" in\n    restart_klipper)   restart_klipper ;;\n    restart_moonraker) restart_moonraker ;;\n    restart_nginx)     restart_nginx ;;\n    restart_camera)    restart_camera ;;\n    show_installed)    show_installed ;;\nesac\n")
print("  OK scripts/system.sh")

open("scripts/shapers.sh", "w").write("#!/bin/sh\n# shapers.sh - Improved Shapers Calibrations for K2 Plus (LIS2DW accelerometer)\n# Includes all K1 Max shaper macros adapted for K2 Plus hardware\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\nSHAPERS_CFG=$CONFIG_DIR/shapers_calibration.cfg\n\ninstall_shapers() {\n    echo \"\"\n    log_info \"Installing Improved Shapers Calibrations...\"\n    echo \"\"\n\n    cat > \"$SHAPERS_CFG\" << 'EOF'\n# Improved Shapers Calibrations \u2014 K2 Plus\n# Managed by Creality Helper Script\n#\n# Hardware: LIS2DW accelerometer on nozzle_mcu via SPI\n#   CS: nozzle_mcu:PA4 | SCLK: nozzle_mcu:PA5\n#   MOSI: nozzle_mcu:PA7 | MISO: nozzle_mcu:PA6\n#   Axes map: x,z,y | Probe point: 175,175,175\n#\n# Macros included:\n#   INPUT_SHAPER_CALIBRATION  - full X+Y calibration (recommended)\n#   SHAPER_CALIBRATE_X        - X axis only\n#   SHAPER_CALIBRATE_Y        - Y axis only\n#   BELTS_SHAPER_CALIBRATION  - belt tension analysis via frequency profile\n#   EXCITATE_AXIS_AT_FREQ     - hold excitation at a specific frequency for diagnosis\n#   AUTOTUNE_SHAPERS          - apply and save recommended shaper settings\n#   TEST_RESONANCES_GRAPHS    - generate CSV data for external analysis\n#   RESTORE_SHAPERS           - restore previously saved shaper settings\n\n# \u2500\u2500 Full calibration (recommended workflow) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro INPUT_SHAPER_CALIBRATION]\ndescription: Run full X and Y resonance test and save recommended shaper settings\ngcode:\n  {% if printer.toolhead.homed_axes != \"xyz\" %}\n    {action_respond_info(\"Homing printer first...\")}\n    G28\n  {% endif %}\n\n  {action_respond_info(\"Starting input shaper calibration for X and Y axes...\")}\n  {action_respond_info(\"This will take several minutes. Keep the printer still.\")}\n\n  SHAPER_CALIBRATE\n\n  {action_respond_info(\"Calibration complete. Run SAVE_CONFIG to apply the results.\")}\n  {action_respond_info(\"Or run AUTOTUNE_SHAPERS to apply and save automatically.\")}\n\n# \u2500\u2500 Per-axis calibration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro SHAPER_CALIBRATE_X]\ndescription: Run resonance test on X axis only\ngcode:\n  {% if printer.toolhead.homed_axes != \"xyz\" %}\n    G28\n  {% endif %}\n  {action_respond_info(\"Testing X axis resonances...\")}\n  SHAPER_CALIBRATE AXIS=X\n  {action_respond_info(\"X axis test complete. Run SAVE_CONFIG to apply.\")}\n\n[gcode_macro SHAPER_CALIBRATE_Y]\ndescription: Run resonance test on Y axis only\ngcode:\n  {% if printer.toolhead.homed_axes != \"xyz\" %}\n    G28\n  {% endif %}\n  {action_respond_info(\"Testing Y axis resonances...\")}\n  SHAPER_CALIBRATE AXIS=Y\n  {action_respond_info(\"Y axis test complete. Run SAVE_CONFIG to apply.\")}\n\n# \u2500\u2500 Belt tension analysis \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# K2 Plus has dual belts (X and Y CoreXY).\n# This macro performs a low-frequency sweep on each axis to compare the\n# frequency profiles of individual belts, helping diagnose uneven tension.\n# Target belt tension: 140N (see [belt_mdl] in printer.cfg)\n\n[gcode_macro BELTS_SHAPER_CALIBRATION]\ndescription: Analyse belt tension via frequency sweep. Compare X and Y profiles.\nvariable_min_freq: 5.0\nvariable_max_freq: 60.0\nvariable_hz_per_sec: 1.0\nvariable_accel_per_hz: 200.0\ngcode:\n  {% if printer.toolhead.homed_axes != \"xyz\" %}\n    G28\n  {% endif %}\n\n  {action_respond_info(\"Starting belt tension analysis...\")}\n  {action_respond_info(\"Min freq: %.1fHz  Max freq: %.1fHz\" % (printer['gcode_macro BELTS_SHAPER_CALIBRATION'].min_freq, printer['gcode_macro BELTS_SHAPER_CALIBRATION'].max_freq))}\n  {action_respond_info(\"Both axes should show similar frequency peaks if belt tension is balanced.\")}\n  {action_respond_info(\"Unbalanced peaks indicate one belt is tighter/looser than the other.\")}\n  {action_respond_info(\"Target belt tension: 140N (check Settings > Self-check > Belt Tension)\")}\n\n  TEST_RESONANCES AXIS=X OUTPUT=raw_data NAME=belt_x \\\n    FREQ_START={printer['gcode_macro BELTS_SHAPER_CALIBRATION'].min_freq} \\\n    FREQ_END={printer['gcode_macro BELTS_SHAPER_CALIBRATION'].max_freq} \\\n    HZ_PER_SEC={printer['gcode_macro BELTS_SHAPER_CALIBRATION'].hz_per_sec} \\\n    ACCEL_PER_HZ={printer['gcode_macro BELTS_SHAPER_CALIBRATION'].accel_per_hz}\n\n  TEST_RESONANCES AXIS=Y OUTPUT=raw_data NAME=belt_y \\\n    FREQ_START={printer['gcode_macro BELTS_SHAPER_CALIBRATION'].min_freq} \\\n    FREQ_END={printer['gcode_macro BELTS_SHAPER_CALIBRATION'].max_freq} \\\n    HZ_PER_SEC={printer['gcode_macro BELTS_SHAPER_CALIBRATION'].hz_per_sec} \\\n    ACCEL_PER_HZ={printer['gcode_macro BELTS_SHAPER_CALIBRATION'].accel_per_hz}\n\n  {action_respond_info(\"Belt analysis complete.\")}\n  {action_respond_info(\"CSV files saved to /mnt/UDISK/printer_data/config/\")}\n  {action_respond_info(\"Download and plot both files to compare belt frequency profiles.\")}\n\n# \u2500\u2500 Excitation at fixed frequency (vibration diagnosis) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Hold a specific frequency to locate vibration sources (rattles, loose parts).\n# Move around the printer while it vibrates to find the source.\n\n[gcode_macro EXCITATE_AXIS_AT_FREQ]\ndescription: Hold axis excitation at a fixed frequency for vibration diagnosis\ngcode:\n  {% set axis  = params.AXIS|default(\"X\")|upper %}\n  {% set freq  = params.FREQ|default(25)|float %}\n  {% set time  = params.TIME|default(10)|int %}\n  {% set accel = params.ACCEL|default(5000)|float %}\n\n  {% if printer.toolhead.homed_axes != \"xyz\" %}\n    G28\n  {% endif %}\n\n  {action_respond_info(\"Exciting %s axis at %.1fHz for %ds\" % (axis, freq, time))}\n  {action_respond_info(\"Listen/feel for rattles and loose parts while it vibrates.\")}\n\n  TEST_RESONANCES AXIS={axis} \\\n    FREQ_START={freq} \\\n    FREQ_END={freq + 0.1} \\\n    HZ_PER_SEC=0.01 \\\n    ACCEL_PER_HZ={accel} \\\n    OUTPUT=raw_data\n\n  {action_respond_info(\"Excitation complete.\")}\n\n# \u2500\u2500 Apply and save recommended shapers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro AUTOTUNE_SHAPERS]\ndescription: Apply and save the recommended shaper settings from the last calibration\ngcode:\n  {action_respond_info(\"Saving shaper calibration results to printer.cfg...\")}\n  SAVE_CONFIG\n  {action_respond_info(\"Shaper settings saved. Klipper will restart to apply.\")}\n\n# \u2500\u2500 Generate raw CSV data for external analysis \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro TEST_RESONANCES_GRAPHS]\ndescription: Generate raw resonance CSV data for both axes for external analysis\ngcode:\n  {% if printer.toolhead.homed_axes != \"xyz\" %}\n    G28\n  {% endif %}\n\n  {action_respond_info(\"Generating resonance data for X axis...\")}\n  TEST_RESONANCES AXIS=X OUTPUT=raw_data NAME=resonance_x\n\n  {action_respond_info(\"Generating resonance data for Y axis...\")}\n  TEST_RESONANCES AXIS=Y OUTPUT=raw_data NAME=resonance_y\n\n  {action_respond_info(\"Done. CSV files saved to /mnt/UDISK/printer_data/config/\")}\n  {action_respond_info(\"Download via Fluidd file manager for analysis with Klipper's calibrate_shaper.py\")}\n\n# \u2500\u2500 Restore saved shaper settings \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro RESTORE_SHAPERS]\ndescription: Restore the shaper settings from printer.cfg SAVE_CONFIG block\ngcode:\n  {action_respond_info(\"Restoring shaper settings from SAVE_CONFIG block...\")}\n  {% set x_type  = printer.configfile.settings.input_shaper.shaper_type_x %}\n  {% set x_freq  = printer.configfile.settings.input_shaper.shaper_freq_x %}\n  {% set y_type  = printer.configfile.settings.input_shaper.shaper_type_y %}\n  {% set y_freq  = printer.configfile.settings.input_shaper.shaper_freq_y %}\n  SET_INPUT_SHAPER SHAPER_TYPE_X={x_type} SHAPER_FREQ_X={x_freq} SHAPER_TYPE_Y={y_type} SHAPER_FREQ_Y={y_freq}\n  {action_respond_info(\"Restored: X=%s @ %.1fHz  Y=%s @ %.1fHz\" % (x_type, x_freq, y_type, y_freq))}\n\n# \u2500\u2500 Quick status check \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro SHAPER_STATUS]\ndescription: Show current active input shaper settings\ngcode:\n  {% set x_type = printer.configfile.settings.input_shaper.shaper_type_x %}\n  {% set x_freq = printer.configfile.settings.input_shaper.shaper_freq_x %}\n  {% set y_type = printer.configfile.settings.input_shaper.shaper_type_y %}\n  {% set y_freq = printer.configfile.settings.input_shaper.shaper_freq_y %}\n  {action_respond_info(\"Input Shaper status:\")}\n  {action_respond_info(\"  X: %s @ %.1f Hz\" % (x_type, x_freq))}\n  {action_respond_info(\"  Y: %s @ %.1f Hz\" % (y_type, y_freq))}\nEOF\n\n    add_include_to_printer_cfg \"shapers_calibration.cfg\"\n    restart_klipper\n\n    mark_installed \"improved_shapers\"\n    echo \"\"\n    log_success \"Improved Shapers Calibrations installed!\"\n    echo \"\"\n    echo \"  Available macros:\"\n    echo -e \"  ${GREEN}Full calibration:${NC}   INPUT_SHAPER_CALIBRATION\"\n    echo -e \"  ${GREEN}Per-axis:${NC}           SHAPER_CALIBRATE_X  |  SHAPER_CALIBRATE_Y\"\n    echo -e \"  ${GREEN}Belt analysis:${NC}      BELTS_SHAPER_CALIBRATION\"\n    echo -e \"  ${GREEN}Diagnosis:${NC}          EXCITATE_AXIS_AT_FREQ [AXIS=X] [FREQ=25] [TIME=10]\"\n    echo -e \"  ${GREEN}Raw data:${NC}           TEST_RESONANCES_GRAPHS\"\n    echo -e \"  ${GREEN}Apply & save:${NC}       AUTOTUNE_SHAPERS\"\n    echo -e \"  ${GREEN}Restore:${NC}            RESTORE_SHAPERS\"\n    echo -e \"  ${GREEN}Status:${NC}             SHAPER_STATUS\"\n    echo \"\"\n    log_info \"Recommended workflow:\"\n    echo \"  1. Run INPUT_SHAPER_CALIBRATION\"\n    echo \"  2. Review results in console\"\n    echo \"  3. Run AUTOTUNE_SHAPERS to save\"\n    echo \"\"\n    log_info \"Belt tension check: Settings \u2192 Self-check \u2192 Belt Tension (target: 140N)\"\n    echo \"\"\n}\n\nremove_shapers() {\n    echo \"\"\n    log_info \"Removing Improved Shapers Calibrations...\"\n    remove_include_from_printer_cfg \"shapers_calibration.cfg\"\n    rm -f \"$SHAPERS_CFG\"\n    restart_klipper\n    mark_removed \"improved_shapers\"\n    log_success \"Improved Shapers Calibrations removed.\"\n    echo \"\"\n}\n\ncase \"$1\" in\n    install) install_shapers ;;\n    remove)  remove_shapers ;;\n    *)       echo \"Usage: $0 [install|remove]\" ;;\nesac\n")
print("  OK scripts/shapers.sh")

open("scripts/fans.sh", "w").write("#!/bin/sh\n# fans.sh - Install/remove Fans Control Macros for K2 Plus\n\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\n\nFANS_CFG=$CONFIG_DIR/fans_control.cfg\n\ninstall_fans() {\n    echo \"\"\n    log_info \"Installing Fans Control Macros...\"\n    echo \"\"\n\n    cat > \"$FANS_CFG\" << 'EOF'\n# Fans Control Macros \u2014 K2 Plus\n# Managed by Creality Helper Script\n# Part cooling: fan0 (nozzle_mcu:PB15, enable nozzle_mcu:PB6)\n# Aux fan:      fan2 (PB4+PB3)\n# Chamber fan:  chamber_fan (PA0, temperature_fan, watermark)\n# Chamber heat: chamber_heater (PC12, heater_generic)\n\n# \u2500\u2500 Save / Restore fan state \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro SAVE_FANS]\ndescription: Save current fan speeds\nvariable_fan0_speed: 0\nvariable_fan2_speed: 0\ngcode:\n  SET_GCODE_VARIABLE MACRO=SAVE_FANS VARIABLE=fan0_speed VALUE={printer['output_pin fan0'].value}\n  SET_GCODE_VARIABLE MACRO=SAVE_FANS VARIABLE=fan2_speed VALUE={printer['output_pin fan2'].value}\n\n[gcode_macro RESTORE_FANS]\ndescription: Restore previously saved fan speeds\ngcode:\n  {% set s = printer['gcode_macro SAVE_FANS'] %}\n  SET_FAN0 S={( s.fan0_speed * 255 )|int}\n  SET_FAN2 S={( s.fan2_speed * 255 )|int}\n\n# \u2500\u2500 Part cooling fan (fan0) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro SET_FAN0]\ndescription: Set part cooling fan speed. S=0-255\ngcode:\n  {% set speed = params.S|default(0)|int %}\n  {% set pwm = (speed / 255.0)|round(4) %}\n  SET_PIN PIN=fan0_en VALUE={% if speed > 0 %}1{% else %}0{% endif %}\n  SET_PIN PIN=fan0 VALUE={pwm}\n\n# \u2500\u2500 Aux fan (fan2) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro SET_FAN2]\ndescription: Set aux fan speed. S=0-255\ngcode:\n  {% set speed = params.S|default(0)|int %}\n  {% set pwm = (speed / 255.0)|round(4) %}\n  SET_PIN PIN=fan2 VALUE={pwm}\n\n# \u2500\u2500 Turn off all output fans \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro FANS_OFF]\ndescription: Turn off all output fans (does not affect hotend_fan auto-control)\ngcode:\n  SET_FAN0 S=0\n  SET_FAN2 S=0\n\n# \u2500\u2500 Chamber heater control \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro CHAMBER_HEAT]\ndescription: Set chamber heater target. Use WAIT=1 to wait for temp. TARGET=degrees\nvariable_chamber_target: 0\ngcode:\n  {% set target = params.TARGET|default(0)|float %}\n  {% set wait = params.WAIT|default(0)|int %}\n  SET_HEATER_TEMPERATURE HEATER=chamber_heater TARGET={target}\n  SET_GCODE_VARIABLE MACRO=CHAMBER_HEAT VARIABLE=chamber_target VALUE={target}\n  {% if wait == 1 and target > 0 %}\n    TEMPERATURE_WAIT SENSOR=\"heater_generic chamber_heater\" MINIMUM={target - 3}\n    {action_respond_info(\"Chamber reached target temperature: %d\u00b0C\" % target)}\n  {% endif %}\n\n[gcode_macro CHAMBER_COOL]\ndescription: Disable chamber heater and run cooling fan at full speed\ngcode:\n  SET_HEATER_TEMPERATURE HEATER=chamber_heater TARGET=0\n  SET_TEMPERATURE_FAN_TARGET TEMPERATURE_FAN=chamber_fan TARGET=20\n  {action_respond_info(\"Chamber cooling: heater off, fan at full speed\")}\n\n# \u2500\u2500 Convenience: chamber temperature status \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n[gcode_macro CHAMBER_STATUS]\ndescription: Print current chamber temperature and target\ngcode:\n  {% set chamber_temp = printer['heater_generic chamber_heater'].temperature %}\n  {% set chamber_target = printer['heater_generic chamber_heater'].target %}\n  {action_respond_info(\"Chamber: %.1f\u00b0C / target: %.1f\u00b0C\" % (chamber_temp, chamber_target))}\nEOF\n\n    add_include_to_printer_cfg \"fans_control.cfg\"\n    restart_klipper\n\n    mark_installed \"fans_control_macros\"\n    echo \"\"\n    log_success \"Fans Control Macros installed!\"\n    echo \"\"\n    log_info \"Available macros: SET_FAN0, SET_FAN2, FANS_OFF, SAVE_FANS, RESTORE_FANS\"\n    log_info \"Chamber macros:   CHAMBER_HEAT, CHAMBER_COOL, CHAMBER_STATUS\"\n    echo \"\"\n}\n\nremove_fans() {\n    echo \"\"\n    log_info \"Removing Fans Control Macros...\"\n    remove_include_from_printer_cfg \"fans_control.cfg\"\n    rm -f \"$FANS_CFG\"\n    restart_klipper\n    mark_removed \"fans_control_macros\"\n    log_success \"Fans Control Macros removed.\"\n    echo \"\"\n}\n\ncase \"$1\" in\n    install) install_fans ;;\n    remove)  remove_fans ;;\n    *)       echo \"Usage: $0 [install|remove]\" ;;\nesac\n")
print("  OK scripts/fans.sh")

open("scripts/backup.sh", "w").write("#!/bin/sh\n# backup.sh - Backup and restore Klipper configuration for K2 Plus\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\n\nBACKUP_DIR=/mnt/UDISK/helper-script/backups\n\nbackup_config() {\n    echo \"\"\n    log_info \"Backing up Klipper configuration...\"\n    mkdir -p \"$BACKUP_DIR\"\n\n    TIMESTAMP=$(date +%Y%m%d_%H%M%S)\n    BACKUP_FILE=\"$BACKUP_DIR/klipper_config_${TIMESTAMP}.tar.gz\"\n\n    tar -czf \"$BACKUP_FILE\" -C /mnt/UDISK/printer_data config/\n\n    if [ $? -eq 0 ]; then\n        echo \"\"\n        log_success \"Backup saved to: $BACKUP_FILE\"\n        SIZE=$(du -sh \"$BACKUP_FILE\" | cut -f1)\n        log_info \"Backup size: $SIZE\"\n        echo \"\"\n\n        # Keep only last 5 backups\n        ls -t \"$BACKUP_DIR\"/*.tar.gz 2>/dev/null | tail -n +6 | xargs rm -f 2>/dev/null\n        log_info \"Keeping last 5 backups. Older backups removed.\"\n    else\n        log_error \"Backup failed.\"\n    fi\n    echo \"\"\n}\n\nrestore_config() {\n    echo \"\"\n    log_info \"Available backups:\"\n    echo \"\"\n\n    if [ ! -d \"$BACKUP_DIR\" ] || [ -z \"$(ls \"$BACKUP_DIR\"/*.tar.gz 2>/dev/null)\" ]; then\n        log_warn \"No backups found in $BACKUP_DIR\"\n        return 1\n    fi\n\n    i=1\n    for f in $(ls -t \"$BACKUP_DIR\"/*.tar.gz 2>/dev/null); do\n        SIZE=$(du -sh \"$f\" | cut -f1)\n        DATE=$(basename \"$f\" .tar.gz | sed 's/klipper_config_//' | sed 's/_/ /')\n        echo \"  $i) $DATE  [$SIZE]\"\n        eval \"BACKUP_$i=$f\"\n        i=$((i+1))\n    done\n\n    echo \"  0) Cancel\"\n    echo \"\"\n    printf \"  Select backup to restore: \"\n    read choice\n\n    if [ \"$choice\" = \"0\" ] || [ -z \"$choice\" ]; then\n        log_info \"Cancelled.\"\n        return 0\n    fi\n\n    eval \"SELECTED=\\$BACKUP_$choice\"\n    if [ -z \"$SELECTED\" ]; then\n        log_error \"Invalid selection.\"\n        return 1\n    fi\n\n    echo \"\"\n    echo -e \"${YELLOW}WARNING: This will overwrite your current config files.${NC}\"\n    printf \"Are you sure? [y/N]: \"\n    read confirm\n    if [ \"$confirm\" != \"y\" ] && [ \"$confirm\" != \"Y\" ]; then\n        log_info \"Cancelled.\"\n        return 0\n    fi\n\n    log_info \"Restoring from: $(basename $SELECTED)...\"\n    tar -xzf \"$SELECTED\" -C /mnt/UDISK/printer_data/\n\n    if [ $? -eq 0 ]; then\n        log_success \"Config restored successfully.\"\n        restart_klipper\n    else\n        log_error \"Restore failed.\"\n    fi\n    echo \"\"\n}\n\ncase \"$1\" in\n    backup)  backup_config ;;\n    restore) restore_config ;;\n    *)       echo \"Usage: $0 [backup|restore]\" ;;\nesac\n")
print("  OK scripts/backup.sh")

open("scripts/m600.sh", "w").write("#!/bin/sh\n# m600.sh - M600 filament change support for K2 Plus\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\nM600_CFG=$CONFIG_DIR/m600.cfg\n\ninstall_m600() {\n    echo \"\"\n    log_info \"Installing M600 Support...\"\n    cat > \"$M600_CFG\" << 'EOF'\n# M600 Filament Change \u2014 K2 Plus\n# In CFS/multi-material mode, tool changes are handled by BOX_* macros.\n# This M600 is for single-filament manual filament changes.\n\n[gcode_macro M600]\ndescription: Filament change \u2014 pause, retract, wait for manual swap\nvariable_park_x: 10\nvariable_park_y: 10\nvariable_retract: 5\ngcode:\n  {% set x = printer['gcode_macro M600'].park_x %}\n  {% set y = printer['gcode_macro M600'].park_y %}\n  {% set e = printer['gcode_macro M600'].retract %}\n\n  SAVE_GCODE_STATE NAME=M600_STATE\n\n  ; Retract\n  {% if printer.extruder.can_extrude %}\n    G91\n    G1 E-{e} F3600\n    G90\n  {% endif %}\n\n  ; Park\n  {% set z_pos = printer.toolhead.position.z %}\n  {% set z_target = [z_pos + 10, printer.toolhead.axis_maximum.z]|min %}\n  G90\n  G1 Z{z_target} F600\n  G1 X{x} Y{y} F12000\n\n  ; Pause heater slightly to avoid ooze, keep it warm\n  {% set temp = printer.extruder.target %}\n  M104 S{[temp - 20, 160]|max}\n\n  PAUSE_BASE\n\n  {action_respond_info(\"M600: Filament change paused. Swap filament then RESUME.\")}\n\n[gcode_macro FILAMENT_LOAD]\ndescription: Load filament \u2014 heat and extrude\ngcode:\n  {% set temp = params.TEMP|default(200)|float %}\n  M109 S{temp}\n  G91\n  G1 E80 F300\n  G1 E30 F150\n  G90\n  {action_respond_info(\"Filament loaded.\")}\n\n[gcode_macro FILAMENT_UNLOAD]\ndescription: Unload filament \u2014 heat, retract, pull\ngcode:\n  {% set temp = params.TEMP|default(200)|float %}\n  M109 S{temp}\n  G91\n  G1 E5 F300\n  G1 E-80 F1800\n  G90\n  {action_respond_info(\"Filament unloaded.\")}\nEOF\n    add_include_to_printer_cfg \"m600.cfg\"\n    restart_klipper\n    mark_installed \"m600_support\"\n    echo \"\"\n    log_success \"M600 Support installed!\"\n    log_info \"Set slicer change filament G-code to: M600\"\n    echo \"\"\n}\n\nremove_m600() {\n    remove_include_from_printer_cfg \"m600.cfg\"\n    rm -f \"$M600_CFG\"\n    restart_klipper\n    mark_removed \"m600_support\"\n    log_success \"M600 Support removed.\"\n}\n\ncase \"$1\" in\n    install) install_m600 ;;\n    remove)  remove_m600 ;;\nesac\n")
print("  OK scripts/m600.sh")

open("scripts/z_offset.sh", "w").write("#!/bin/sh\n# z_offset.sh - Save Z-Offset Macros for K2 Plus\nSCRIPT_DIR=/mnt/UDISK/helper-script\n. \"$SCRIPT_DIR/scripts/system.sh\"\nZ_CFG=$CONFIG_DIR/z_offset_macros.cfg\n\ninstall_z_offset() {\n    echo \"\"\n    log_info \"Installing Save Z-Offset Macros...\"\n    cat > \"$Z_CFG\" << 'EOF'\n# Save Z-Offset Macros \u2014 K2 Plus (prtouch_v3 strain-gauge probe)\n\n[gcode_macro SAVE_Z_OFFSET]\ndescription: Save current live Z offset to printer.cfg\ngcode:\n  Z_OFFSET_APPLY_PROBE\n  SAVE_CONFIG\n\n[gcode_macro SET_Z_OFFSET]\ndescription: Apply a Z offset value and save. Usage: SET_Z_OFFSET Z=0.05\ngcode:\n  {% set z = params.Z|default(0)|float %}\n  SET_GCODE_OFFSET Z={z} MOVE=1\n  {action_respond_info(\"Z offset set to %.3f \u2014 run SAVE_Z_OFFSET to persist\" % z)}\n\n[gcode_macro RESET_Z_OFFSET]\ndescription: Reset Z offset to 0\ngcode:\n  SET_GCODE_OFFSET Z=0 MOVE=1\n  {action_respond_info(\"Z offset reset to 0\")}\nEOF\n    add_include_to_printer_cfg \"z_offset_macros.cfg\"\n    restart_klipper\n    mark_installed \"z_offset_macros\"\n    echo \"\"\n    log_success \"Save Z-Offset Macros installed!\"\n    echo \"\"\n}\n\nremove_z_offset() {\n    remove_include_from_printer_cfg \"z_offset_macros.cfg\"\n    rm -f \"$Z_CFG\"\n    restart_klipper\n    mark_removed \"z_offset_macros\"\n    log_success \"Z-Offset Macros removed.\"\n}\n\ncase \"$1\" in\n    install) install_z_offset ;;\n    remove)  remove_z_offset ;;\nesac\n")
print("  OK scripts/z_offset.sh")

open("helper.sh", "w").write("#!/bin/sh\n# Creality K2 Plus Helper Script\n# https://github.com/sw3defy/Creality-Helper-Script-Wiki-K2-Plus\n# Compatible with: Creality K2 Plus, K2 Plus Combo\n# OS: Tina 5.0 / OpenWrt 21.02\n\nSCRIPT_DIR=/mnt/UDISK/helper-script\nSCRIPTS_DIR=$SCRIPT_DIR/scripts\nFILES_DIR=$SCRIPT_DIR/files\nPRINTER_DATA=/mnt/UDISK/printer_data\nCONFIG_DIR=$PRINTER_DATA/config\nLOGS_DIR=$PRINTER_DATA/logs\n\n# Colors\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nCYAN='\\033[0;36m'\nWHITE='\\033[1;37m'\nNC='\\033[0m'\n\nprint_header() {\n    clear\n    echo \"\"\n    echo -e \"${CYAN}======================================================${NC}\"\n    echo -e \"${WHITE}   Creality K2 Plus Helper Script${NC}\"\n    echo -e \"${CYAN}======================================================${NC}\"\n    echo -e \"${YELLOW}   https://sw3defy.github.io/Creality-Helper-Script-Wiki-K2-Plus${NC}\"\n    echo -e \"${CYAN}======================================================${NC}\"\n    echo \"\"\n}\n\ncheck_root() {\n    if [ \"$(id -u)\" != \"0\" ]; then\n        echo -e \"${RED}ERROR: This script must be run as root.${NC}\"\n        exit 1\n    fi\n}\n\ncheck_printer() {\n    if [ ! -f \"$CONFIG_DIR/printer.cfg\" ]; then\n        echo -e \"${RED}ERROR: printer.cfg not found at $CONFIG_DIR/printer.cfg${NC}\"\n        echo \"Make sure the printer has booted fully before running this script.\"\n        exit 1\n    fi\n}\n\nmain_menu() {\n    print_header\n    echo -e \"  ${WHITE}[Install] Menu${NC}\"\n    echo -e \"  ${YELLOW}--- Step 1: Foundation (install first) ---${NC}\"\n    echo -e \"    1) Moonraker Extensions & Update Manager  ${GREEN}[recommended first]${NC}\"\n    echo \"\"\n    echo -e \"  ${YELLOW}--- Step 2: Print macros ---${NC}\"\n    echo -e \"    2) Fans Control Macros                    ${CYAN}[needed by START_PRINT]${NC}\"\n    echo \"    3) Useful Macros (START_PRINT / END_PRINT)\"\n    echo \"    4) Save Z-Offset Macros\"\n    echo \"    5) M600 Filament Change Support\"\n    echo \"\"\n    echo -e \"  ${YELLOW}--- Step 3: Leveling & calibration ---${NC}\"\n    echo \"    6) Klipper Adaptive Meshing & Purging (KAMP)\"\n    echo \"    7) Improved Shapers Calibrations\"\n    echo \"\"\n    echo -e \"  ${YELLOW}--- Step 4: Web interface & camera ---${NC}\"\n    echo \"    8) Fluidd (install/update/repair \u2014 port 4408)\"\n    echo -e \"    9) Mainsail (install/update/repair \u2014 port 4409)\"\n    echo \"   10) Moonraker Timelapse\"\n    echo \"\"\n    echo -e \"  ${YELLOW}--- Step 5: Remote access & notifications ---${NC}\"\n    echo \"   11) OctoEverywhere\"\n    echo \"   12) Mobileraker Companion\"\n    echo \"   13) Git Backup\"\n    echo \"\"\n    echo -e \"  ${WHITE}[Remove] Menu${NC}\"\n    echo \"   14) Remove a feature\"\n    echo \"\"\n    echo -e \"  ${WHITE}[Backup & Restore] Menu${NC}\"\n    echo \"   15) Backup Klipper configuration\"\n    echo \"   16) Restore Klipper configuration\"\n    echo \"\"\n    echo -e \"  ${WHITE}[Tools] Menu${NC}\"\n    echo \"   17) Restart Klipper\"\n    echo \"   18) Restart Moonraker\"\n    echo \"   19) Restart Nginx\"\n    echo \"   20) View Klipper log\"\n    echo \"   21) View Moonraker log\"\n    echo \"   22) Show installed features\"\n    echo \"\"\n    echo \"    0) Exit\"\n    echo \"\"\n    printf \"  Enter choice: \"\n    read choice\n    handle_choice \"$choice\"\n}\n\nhandle_choice() {\n    case \"$1\" in\n        # Step 1 \u2014 Foundation\n        1)  sh \"$SCRIPTS_DIR/moonraker.sh\" install ;;\n        # Step 2 \u2014 Print macros (fans before useful_macros \u2014 chamber refs)\n        2)  sh \"$SCRIPTS_DIR/fans.sh\" install ;;\n        3)  sh \"$SCRIPTS_DIR/useful_macros.sh\" install ;;\n        4)  sh \"$SCRIPTS_DIR/z_offset.sh\" install ;;\n        5)  sh \"$SCRIPTS_DIR/m600.sh\" install ;;\n        # Step 3 \u2014 Leveling & calibration\n        6)  sh \"$SCRIPTS_DIR/kamp.sh\" install ;;\n        7)  sh \"$SCRIPTS_DIR/shapers.sh\" install ;;\n        # Step 4 \u2014 Web interface & camera\n        8)  sh \"$SCRIPTS_DIR/fluidd.sh\" install ;;\n        9)  sh \"$SCRIPTS_DIR/mainsail.sh\" install ;;\n        10) sh \"$SCRIPTS_DIR/timelapse.sh\" install ;;\n        # Step 5 \u2014 Remote access\n        11) sh \"$SCRIPTS_DIR/octoeverywhere.sh\" install ;;\n        12) sh \"$SCRIPTS_DIR/mobileraker.sh\" install ;;\n        13) sh \"$SCRIPTS_DIR/git_backup.sh\" install ;;\n        # Other menus\n        14) remove_menu ;;\n        15) sh \"$SCRIPTS_DIR/backup.sh\" backup ;;\n        16) sh \"$SCRIPTS_DIR/backup.sh\" restore ;;\n        17) sh \"$SCRIPTS_DIR/system.sh\" restart_klipper ;;\n        18) sh \"$SCRIPTS_DIR/system.sh\" restart_moonraker ;;\n        19) sh \"$SCRIPTS_DIR/system.sh\" restart_nginx ;;\n        20) tail -50 \"$LOGS_DIR/klippy.log\" | less ;;\n        21) tail -50 \"$LOGS_DIR/moonraker.log\" | less ;;\n        22) sh \"$SCRIPTS_DIR/system.sh\" show_installed ;;\n        0)  echo \"\"; echo \"Goodbye!\"; echo \"\"; exit 0 ;;\n        *)  echo -e \"${RED}Invalid choice.${NC}\"; sleep 1 ;;\n    esac\n    echo \"\"\n    printf \"Press Enter to return to menu...\"\n    read dummy\n    main_menu\n}\n\nremove_menu() {\n    print_header\n    echo -e \"  ${WHITE}[Remove] Menu${NC}\"\n    echo \"\"\n    echo \"    1) Moonraker Extensions\"\n    echo \"    2) Fans Control Macros\"\n    echo \"    3) Useful Macros\"\n    echo \"    4) Save Z-Offset Macros\"\n    echo \"    5) M600 Support\"\n    echo \"    6) KAMP\"\n    echo \"    7) Improved Shapers Calibrations\"\n    echo \"    8) Fluidd\"\n    echo -e \"    9) Mainsail (install/update/repair \u2014 port 4409)\"\n    echo \"   10) Moonraker Timelapse\"\n    echo \"   11) OctoEverywhere\"\n    echo \"   12) Mobileraker Companion\"\n    echo \"   13) Git Backup\"\n    echo \"    0) Back\"\n    echo \"\"\n    printf \"  Enter choice: \"\n    read choice\n    case \"$choice\" in\n        1)  sh \"$SCRIPTS_DIR/moonraker.sh\" remove ;;\n        2)  sh \"$SCRIPTS_DIR/fans.sh\" remove ;;\n        3)  sh \"$SCRIPTS_DIR/useful_macros.sh\" remove ;;\n        4)  sh \"$SCRIPTS_DIR/z_offset.sh\" remove ;;\n        5)  sh \"$SCRIPTS_DIR/m600.sh\" remove ;;\n        6)  sh \"$SCRIPTS_DIR/kamp.sh\" remove ;;\n        7)  sh \"$SCRIPTS_DIR/shapers.sh\" remove ;;\n        8)  sh \"$SCRIPTS_DIR/fluidd.sh\" remove ;;\n        9)  sh \"$SCRIPTS_DIR/mainsail.sh\" remove ;;\n        10) sh \"$SCRIPTS_DIR/timelapse.sh\" remove ;;\n        11) sh \"$SCRIPTS_DIR/octoeverywhere.sh\" remove ;;\n        12) sh \"$SCRIPTS_DIR/mobileraker.sh\" remove ;;\n        13) sh \"$SCRIPTS_DIR/git_backup.sh\" remove ;;\n        0)  return ;;\n        *)  echo -e \"${RED}Invalid choice.${NC}\" ;;\n    esac\n}\n\n# Entry point\ncheck_root\ncheck_printer\nmain_menu\n")
print("  OK helper.sh")

